<?php
declare(strict_types=1);

abstract class AbstractProcessor {
    abstract public function process(array $data): array;
    public function validate(array $data): bool { return !empty($data); }
}

class JsonProcessor extends AbstractProcessor {
    public function process(array $data): array {
        return array_map('json_encode', $data);
    }

    public function validate(array $data): bool {
        foreach ($data as $item) {
            if (!is_array($item) && !is_scalar($item)) {
                return false;
            }
        }
        return parent::validate($data);
    }
}
